import React from 'react';
import { Link } from 'react-router-dom';
import { 
  FaFacebookF, FaTwitter, FaInstagram, FaLinkedinIn, FaYoutube,
  FaGithub, FaHeart, FaEnvelope, FaPhone, FaMapMarkerAlt,
  FaArrowRight, FaBook, FaFileAlt, FaHistory, FaUpload,
  FaGraduationCap, FaStar, FaUsers, FaDownload, FaCode,
  FaLaptopCode, FaChartLine, FaBriefcase, FaDatabase, FaCloud,
  FaMobileAlt, FaShieldAlt, FaRocket, FaGlobe
} from 'react-icons/fa';

const Footer = () => {
  const styles = {
    footer: {
      background: 'linear-gradient(145deg, #0A1929 0%, #0F2B4A 50%, #1A3B5C 100%)',
      color: 'white',
      padding: '4rem 2rem 1rem',
      marginTop: '4rem',
      position: 'relative',
      overflow: 'hidden',
      borderTop: '4px solid #3B82F6',
      boxShadow: '0 -10px 30px rgba(59, 130, 246, 0.2)'
    },
    // Educational pattern background
    backgroundEffect: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'radial-gradient(circle at 20% 30%, rgba(59, 130, 246, 0.1) 0%, transparent 50%), repeating-linear-gradient(45deg, rgba(255,255,255,0.02) 0px, rgba(255,255,255,0.02) 2px, transparent 2px, transparent 8px)',
      pointerEvents: 'none',
      animation: 'pulse 4s ease-in-out infinite'
    },
    container: {
      maxWidth: '1400px',
      margin: '0 auto',
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
      gap: '2.5rem',
      position: 'relative',
      zIndex: 1
    },
    section: {
      marginBottom: '1.5rem',
      animation: 'fadeInUp 0.6s ease-out'
    },
    title: {
      color: '#3B82F6',
      marginBottom: '1.5rem',
      fontSize: '1.3rem',
      fontWeight: '700',
      position: 'relative',
      paddingBottom: '0.5rem',
      borderBottom: '3px solid rgba(59, 130, 246, 0.3)',
      display: 'inline-block',
      textTransform: 'uppercase',
      letterSpacing: '1px',
      textShadow: '0 2px 4px rgba(0,0,0,0.3)'
    },
    link: {
      color: '#94A3B8',
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      marginBottom: '0.8rem',
      transition: 'all 0.3s ease',
      padding: '0.4rem 0',
      fontSize: '0.95rem',
      fontWeight: '500',
      '&:hover': {
        color: '#3B82F6',
        transform: 'translateX(8px)',
        textShadow: '0 0 8px rgba(59, 130, 246, 0.3)'
      }
    },
    icon: {
      fontSize: '1rem',
      color: '#3B82F6'
    },
    contactItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '1rem',
      marginBottom: '1rem',
      color: '#94A3B8',
      transition: 'all 0.3s ease',
      padding: '0.8rem',
      borderRadius: '10px',
      background: 'rgba(255, 255, 255, 0.03)',
      border: '1px solid rgba(59, 130, 246, 0.2)',
      backdropFilter: 'blur(5px)',
      '&:hover': {
        background: 'rgba(59, 130, 246, 0.1)',
        borderColor: '#3B82F6',
        transform: 'translateY(-3px)'
      }
    },
    socialLinks: {
      display: 'flex',
      gap: '0.8rem',
      marginTop: '1.5rem',
      flexWrap: 'wrap'
    },
    socialIcon: {
      width: '40px',
      height: '40px',
      borderRadius: '50%',
      background: 'rgba(255, 255, 255, 0.05)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: '#3B82F6',
      fontSize: '1.2rem',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid rgba(59, 130, 246, 0.3)',
      '&:hover': {
        background: '#3B82F6',
        color: 'white',
        transform: 'translateY(-5px)',
        boxShadow: '0 5px 15px rgba(59, 130, 246, 0.4)'
      }
    },
    newsletter: {
      marginTop: '1.5rem',
      display: 'flex',
      gap: '0.5rem'
    },
    newsletterInput: {
      flex: 1,
      padding: '0.8rem 1rem',
      borderRadius: '8px',
      border: '2px solid rgba(59, 130, 246, 0.2)',
      background: 'rgba(255, 255, 255, 0.05)',
      color: 'white',
      outline: 'none',
      transition: 'all 0.3s',
      fontSize: '0.9rem',
      '&::placeholder': {
        color: 'rgba(255, 255, 255, 0.5)'
      },
      '&:focus': {
        borderColor: '#3B82F6',
        background: 'rgba(59, 130, 246, 0.1)'
      }
    },
    newsletterBtn: {
      padding: '0.8rem 1.2rem',
      borderRadius: '8px',
      border: 'none',
      background: '#3B82F6',
      color: 'white',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      gap: '0.3rem',
      fontSize: '0.9rem',
      '&:hover': {
        background: '#2563EB',
        transform: 'translateX(3px)'
      }
    },
    bottom: {
      textAlign: 'center',
      paddingTop: '2rem',
      marginTop: '3rem',
      borderTop: '2px solid rgba(59, 130, 246, 0.2)',
      color: '#94A3B8',
      position: 'relative',
      zIndex: 1
    },
    heart: {
      color: '#EF4444',
      animation: 'heartbeat 1.5s ease-in-out infinite',
      display: 'inline-block',
      margin: '0 0.3rem'
    },
    // Educational Stats
    stats: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '1rem',
      marginTop: '1.5rem'
    },
    statBox: {
      background: 'rgba(59, 130, 246, 0.1)',
      padding: '1rem',
      borderRadius: '10px',
      textAlign: 'center',
      transition: 'all 0.3s',
      border: '1px solid rgba(59, 130, 246, 0.2)',
      '&:hover': {
        background: 'rgba(59, 130, 246, 0.2)',
        transform: 'scale(1.05)'
      }
    },
    // Courses Grid
    coursesGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '0.8rem',
      marginTop: '1rem'
    },
    courseItem: {
      background: 'rgba(255, 255, 255, 0.03)',
      padding: '0.8rem',
      borderRadius: '8px',
      textAlign: 'center',
      fontSize: '0.85rem',
      color: '#94A3B8',
      border: '1px solid rgba(59, 130, 246, 0.1)',
      transition: 'all 0.3s',
      cursor: 'pointer',
      textDecoration: 'none',
      display: 'block',
      '&:hover': {
        background: '#3B82F6',
        color: 'white',
        transform: 'translateY(-2px)'
      }
    },
    // Features
    featureItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      marginBottom: '0.8rem',
      color: '#94A3B8',
      fontSize: '0.9rem'
    }
  };

  // Course categories
  const courses = [
    'B.Tech', 'BCA', 'MCA', 'BBA', 'MBA', 'B.Com', 'BA', 'Diploma'
  ];

  // Popular subjects
  const subjects = [
    'Computer Science', 'Mathematics', 'Physics', 'Chemistry',
    'Economics', 'Management', 'Commerce', 'English'
  ];

  // Features
  const features = [
    { icon: <FaRocket />, text: '1000+ Study Notes' },
    { icon: <FaHistory />, text: '500+ PYQs' },
    { icon: <FaGlobe />, text: '50+ Courses' },
    { icon: <FaUsers />, text: '10k+ Students' },
    { icon: <FaCloud />, text: 'Free Access' },
    { icon: <FaShieldAlt />, text: 'Quality Content' }
  ];

  return (
    <footer style={styles.footer}>
      {/* Educational pattern background */}
      <div style={styles.backgroundEffect}></div>

      <div style={styles.container}>
        {/* About & Stats Section */}
        <div style={styles.section}>
          <h3 style={styles.title}>
            <FaGraduationCap style={{ marginRight: '0.5rem' }} /> Study Portal
          </h3>
          <p style={{ color: '#94A3B8', lineHeight: '1.8', marginBottom: '1rem', fontSize: '0.9rem' }}>
            India's leading educational platform providing quality study materials, 
            notes, PYQs, and resources for all courses.
          </p>
          
          {/* Stats */}
          <div style={styles.stats}>
            <div style={styles.statBox}>
              <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#3B82F6' }}>1000+</div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Notes</div>
            </div>
            <div style={styles.statBox}>
              <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#3B82F6' }}>500+</div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>PYQs</div>
            </div>
            <div style={styles.statBox}>
              <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#3B82F6' }}>50+</div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Courses</div>
            </div>
            <div style={styles.statBox}>
              <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#3B82F6' }}>10k+</div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Students</div>
            </div>
          </div>

          {/* Features */}
          <div style={{ marginTop: '1.5rem' }}>
            {features.map((feature, index) => (
              <div key={index} style={styles.featureItem}>
                <span style={{ color: '#3B82F6', fontSize: '1.1rem' }}>{feature.icon}</span>
                <span>{feature.text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Courses & Subjects */}
        <div style={styles.section}>
          <h3 style={styles.title}>Popular Courses</h3>
          <div style={styles.coursesGrid}>
            {courses.map((course, index) => (
              <Link to={`/course/${course.toLowerCase()}`} key={index} style={styles.courseItem}>
                {course}
              </Link>
            ))}
          </div>

          <h3 style={{ ...styles.title, marginTop: '2rem' }}>Popular Subjects</h3>
          <div style={styles.coursesGrid}>
            {subjects.map((subject, index) => (
              <Link to={`/subject/${subject.toLowerCase().replace(' ', '-')}`} key={index} style={styles.courseItem}>
                {subject}
              </Link>
            ))}
          </div>
        </div>

        {/* Quick Links */}
        <div style={styles.section}>
          <h3 style={styles.title}>Quick Links</h3>
          <Link to="/" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Home
          </Link>
          <Link to="/courses" style={styles.link}>
            <FaArrowRight style={styles.icon} /> All Courses
          </Link>
          <Link to="/notes" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Study Notes
          </Link>
          <Link to="/pyqs" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Previous Papers
          </Link>
          <Link to="/syllabus" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Syllabus
          </Link>
          <Link to="/upload" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Upload Material
          </Link>
          <Link to="/about" style={styles.link}>
            <FaArrowRight style={styles.icon} /> About Us
          </Link>
          <Link to="/contact" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Contact
          </Link>
        </div>

        {/* Contact & Social */}
        <div style={styles.section}>
          <h3 style={styles.title}>Get in Touch</h3>
          
          <div style={styles.contactItem}>
            <FaEnvelope style={{ color: '#3B82F6', fontSize: '1.2rem' }} />
            <div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Email</div>
              <div style={{ fontWeight: '500' }}>studyportal@edu.in</div>
            </div>
          </div>

          <div style={styles.contactItem}>
            <FaPhone style={{ color: '#3B82F6', fontSize: '1.2rem' }} />
            <div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Helpline</div>
              <div style={{ fontWeight: '500' }}>1800-123-4567</div>
            </div>
          </div>

          <div style={styles.contactItem}>
            <FaMapMarkerAlt style={{ color: '#3B82F6', fontSize: '1.2rem' }} />
            <div>
              <div style={{ fontSize: '0.75rem', color: '#94A3B8' }}>Address</div>
              <div style={{ fontWeight: '500' }}>Delhi, India</div>
            </div>
          </div>

          {/* Social Links */}
          <div style={styles.socialLinks}>
            <a href="#" style={styles.socialIcon}><FaFacebookF /></a>
            <a href="#" style={styles.socialIcon}><FaTwitter /></a>
            <a href="#" style={styles.socialIcon}><FaInstagram /></a>
            <a href="#" style={styles.socialIcon}><FaLinkedinIn /></a>
            <a href="#" style={styles.socialIcon}><FaYoutube /></a>
          </div>

          {/* Newsletter */}
          <h3 style={{ ...styles.title, marginTop: '2rem' }}>Newsletter</h3>
          <p style={{ color: '#94A3B8', fontSize: '0.85rem', marginBottom: '1rem' }}>
            Get latest study materials and updates
          </p>
          <div style={styles.newsletter}>
            <input 
              type="email" 
              placeholder="Enter your email" 
              style={styles.newsletterInput}
            />
            <button style={styles.newsletterBtn}>
              Subscribe <FaArrowRight />
            </button>
          </div>
        </div>
      </div>

      {/* Bottom Bar */}
      <div style={styles.bottom}>
        <p style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.3rem' }}>
          © 2024 Study Portal. Made with 
          <span style={styles.heart}>❤️</span> 
          for education
        </p>
        <p style={{ fontSize: '0.8rem', marginTop: '0.5rem', color: '#64748B' }}>
          Empowering students with quality education | All rights reserved
        </p>
      </div>

      {/* CSS Animations */}
      <style>
        {`
          @keyframes fadeInUp {
            from {
              opacity: 0;
              transform: translateY(20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          @keyframes heartbeat {
            0%, 100% { transform: scale(1); }
            50% { transform: scale(1.1); }
          }
          
          @keyframes pulse {
            0%, 100% { opacity: 0.3; }
            50% { opacity: 0.6; }
          }
          
          a:hover, button:hover {
            transition: all 0.3s ease;
          }
        `}
      </style>
    </footer>
  );
};

export default Footer;
